document['addEventListener']('DOMContentLoaded',function(){const Y=document['querySelectorAll']('.date-control');Y['forEach']((U,k)=>{U['addEventListener']('keydown',function(T){if('Tab'===T['key']){if(T['preventDefault'](),T['shiftKey']){const W=Y[k-0x1];W&&W['focus']();}else{const G=Y[k+0x1];G&&G['focus']();}}});});});